import{_ as t,o as a,c as o,a2 as n}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 9 — Cursor Movement","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/09-cursor-movement.md","filePath":"chapters/09-cursor-movement.md"}'),s={name:"chapters/09-cursor-movement.md"};function d(r,e,i,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="chapter-9-—-cursor-movement" tabindex="-1">Chapter 9 — Cursor Movement <a class="header-anchor" href="#chapter-9-—-cursor-movement" aria-label="Permalink to &quot;Chapter 9 — Cursor Movement&quot;">​</a></h1><blockquote><p><em>&quot;Moving efficiently through a file is the first skill every Vim user must master.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐ Beginner <strong>Estimated Reading Time:</strong> 15–20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Navigation is the most frequent action you&#39;ll perform in Vim.</p><p>The faster you can move, the faster you can edit.</p><p>This chapter covers:</p><ul><li>Basic cursor movement</li><li>The home row keys (h, j, k, l)</li><li>Combined with counts</li></ul><hr><h1 id="the-home-row" tabindex="-1">The Home Row <a class="header-anchor" href="#the-home-row" aria-label="Permalink to &quot;The Home Row&quot;">​</a></h1><p>Vim places the four most important navigation keys right on the home row:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ↑</span></span>
<span class="line"><span>    k</span></span>
<span class="line"><span>← h   l →</span></span>
<span class="line"><span>    j</span></span>
<span class="line"><span>    ↓</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Key</th><th>Direction</th><th>Finger</th></tr></thead><tbody><tr><td><code>h</code></td><td>Left</td><td>Right index</td></tr><tr><td><code>j</code></td><td>Down</td><td>Right index</td></tr><tr><td><code>k</code></td><td>Up</td><td>Right middle</td></tr><tr><td><code>l</code></td><td>Right</td><td>Right ring</td></tr></tbody></table><p>Keeping your fingers on the home row is faster than reaching for arrow keys.</p><hr><h1 id="moving-one-character" tabindex="-1">Moving One Character <a class="header-anchor" href="#moving-one-character" aria-label="Permalink to &quot;Moving One Character&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>h   →   move left one character</span></span>
<span class="line"><span>j   →   move down one line</span></span>
<span class="line"><span>k   →   move up one line</span></span>
<span class="line"><span>l   →   move right one character</span></span></code></pre></div><h2 id="try-this" tabindex="-1">Try This <a class="header-anchor" href="#try-this" aria-label="Permalink to &quot;Try This&quot;">​</a></h2><p>Open any text file and practice:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>jjjj    (move down 4 lines)</span></span>
<span class="line"><span>kkkk    (move up 4 lines)</span></span>
<span class="line"><span>hhhh    (move left 4 characters)</span></span>
<span class="line"><span>llll    (move right 4 characters)</span></span></code></pre></div><hr><h1 id="arrow-keys" tabindex="-1">Arrow Keys <a class="header-anchor" href="#arrow-keys" aria-label="Permalink to &quot;Arrow Keys&quot;">​</a></h1><p>Arrow keys also work:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>←   →   move left/right</span></span>
<span class="line"><span>↑   ↓   move up/down</span></span></code></pre></div><p>However, they require moving your hand from the home row.</p><p>For now, feel free to use arrow keys. Over time, try to transition to <code>h</code>/<code>j</code>/<code>k</code>/<code>l</code>.</p><hr><h1 id="moving-by-counts" tabindex="-1">Moving by Counts <a class="header-anchor" href="#moving-by-counts" aria-label="Permalink to &quot;Moving by Counts&quot;">​</a></h1><p>Every movement command can be preceded by a number.</p><p>This repeats the movement N times.</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>5j</code></td><td>Move down 5 lines</td></tr><tr><td><code>10k</code></td><td>Move up 10 lines</td></tr><tr><td><code>3h</code></td><td>Move left 3 characters</td></tr><tr><td><code>7l</code></td><td>Move right 7 characters</td></tr></tbody></table><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│ Line 1                          │</span></span>
<span class="line"><span>│ Line 2                          │</span></span>
<span class="line"><span>│ Line 3                          │ ← cursor starts here</span></span>
<span class="line"><span>│ Line 4                          │</span></span>
<span class="line"><span>│ Line 5                          │</span></span>
<span class="line"><span>│ Line 6                          │</span></span>
<span class="line"><span>│ Line 7                          │</span></span>
<span class="line"><span>│ Line 8                          │ ← cursor ends here after 5j</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span></code></pre></div><hr><h1 id="moving-by-words" tabindex="-1">Moving by Words <a class="header-anchor" href="#moving-by-words" aria-label="Permalink to &quot;Moving by Words&quot;">​</a></h1><p>Word movements jump over entire words at a time.</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>w</code></td><td>Forward to <strong>beginning</strong> of next word</td></tr><tr><td><code>W</code></td><td>Forward to next WORD (space-separated)</td></tr><tr><td><code>b</code></td><td>Backward to <strong>beginning</strong> of word</td></tr><tr><td><code>B</code></td><td>Backward to beginning of WORD</td></tr><tr><td><code>e</code></td><td>Forward to <strong>end</strong> of current word</td></tr><tr><td><code>E</code></td><td>Forward to end of WORD</td></tr></tbody></table><h2 id="what-s-the-difference" tabindex="-1">What&#39;s the Difference? <a class="header-anchor" href="#what-s-the-difference" aria-label="Permalink to &quot;What&#39;s the Difference?&quot;">​</a></h2><ul><li><strong>word</strong> (<code>w</code>) — separated by punctuation and spaces</li><li><strong>WORD</strong> (<code>W</code>) — separated only by spaces</li></ul><p>Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hello-world foo</span></span></code></pre></div><ul><li><code>w</code> sees: <code>hello</code> <code>-</code> <code>world</code> <code>foo</code> (4 words)</li><li><code>W</code> sees: <code>hello-world</code> <code>foo</code> (2 WORDS)</li></ul><h2 id="with-counts" tabindex="-1">With Counts <a class="header-anchor" href="#with-counts" aria-label="Permalink to &quot;With Counts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3w      →   forward 3 words</span></span>
<span class="line"><span>5b      →   backward 5 words</span></span>
<span class="line"><span>2e      →   forward to end of next 2 words</span></span></code></pre></div><hr><h1 id="moving-by-lines" tabindex="-1">Moving by Lines <a class="header-anchor" href="#moving-by-lines" aria-label="Permalink to &quot;Moving by Lines&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>0</code></td><td>Go to <strong>first</strong> column of line</td></tr><tr><td><code>^</code></td><td>Go to <strong>first non-blank</strong> character</td></tr><tr><td><code>$</code></td><td>Go to <strong>end</strong> of line</td></tr><tr><td><code>g_</code></td><td>Go to <strong>last non-blank</strong> character</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    0</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>    ┌──────────────────────┐</span></span>
<span class="line"><span>    │    Hello World       │</span></span>
<span class="line"><span>    └──────────────────────┘</span></span>
<span class="line"><span>                          ↑</span></span>
<span class="line"><span>                          $</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ^</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>    ┌──────────────────────┐</span></span>
<span class="line"><span>    │    Hello World       │</span></span>
<span class="line"><span>    └──────────────────────┘</span></span>
<span class="line"><span>                            ↑</span></span>
<span class="line"><span>                            g_</span></span></code></pre></div><h2 id="combined-with-counts" tabindex="-1">Combined with Counts <a class="header-anchor" href="#combined-with-counts" aria-label="Permalink to &quot;Combined with Counts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3$      →   go to end of 3 lines down</span></span></code></pre></div><hr><h1 id="moving-by-screen" tabindex="-1">Moving by Screen <a class="header-anchor" href="#moving-by-screen" aria-label="Permalink to &quot;Moving by Screen&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>H</code></td><td>Jump to <strong>top</strong> of screen</td></tr><tr><td><code>M</code></td><td>Jump to <strong>middle</strong> of screen</td></tr><tr><td><code>L</code></td><td>Jump to <strong>bottom</strong> of screen</td></tr><tr><td><code>zt</code></td><td>Scroll cursor to <strong>top</strong></td></tr><tr><td><code>zz</code></td><td>Scroll cursor to <strong>center</strong></td></tr><tr><td><code>zb</code></td><td>Scroll cursor to <strong>bottom</strong></td></tr><tr><td><code>Ctrl+u</code></td><td>Scroll <strong>up</strong> half screen</td></tr><tr><td><code>Ctrl+d</code></td><td>Scroll <strong>down</strong> half screen</td></tr><tr><td><code>Ctrl+b</code></td><td>Scroll <strong>up</strong> full screen</td></tr><tr><td><code>Ctrl+f</code></td><td>Scroll <strong>down</strong> full screen</td></tr></tbody></table><h2 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h2><p>Instead of scrolling line by line, use these to jump around the visible area instantly.</p><hr><h1 id="practice-exercise" tabindex="-1">Practice Exercise <a class="header-anchor" href="#practice-exercise" aria-label="Permalink to &quot;Practice Exercise&quot;">​</a></h1><p>Open a file and try:</p><ol><li>Move down 10 lines: <code>10j</code></li><li>Move up 5 lines: <code>5k</code></li><li>Jump to end of line: <code>$</code></li><li>Jump to beginning: <code>0</code></li><li>Move forward 3 words: <code>3w</code></li><li>Move backward 2 words: <code>2b</code></li><li>Center the cursor on screen: <code>zz</code></li><li>Scroll half a page: <code>Ctrl+d</code>, <code>Ctrl+u</code></li></ol><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Movement</th></tr></thead><tbody><tr><td><code>h</code></td><td>Left</td></tr><tr><td><code>j</code></td><td>Down</td></tr><tr><td><code>k</code></td><td>Up</td></tr><tr><td><code>l</code></td><td>Right</td></tr><tr><td><code>w</code>/<code>b</code></td><td>Word forward/backward</td></tr><tr><td><code>e</code></td><td>End of word</td></tr><tr><td><code>0</code>/<code>$</code></td><td>Start/end of line</td></tr><tr><td><code>H</code>/<code>M</code>/<code>L</code></td><td>Screen top/mid/bottom</td></tr><tr><td><code>Ctrl+u</code>/<code>Ctrl+d</code></td><td>Scroll up/down</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>h</code>/<code>j</code>/<code>k</code>/<code>l</code> keep your fingers on the home row.</li><li>Precede any movement with a number for repetition.</li><li>Word movements (<code>w</code>, <code>b</code>, <code>e</code>) jump over entire words.</li><li>Line movements (<code>0</code>, <code>$</code>) jump to line edges.</li><li>Screen movements (<code>H</code>, <code>M</code>, <code>L</code>, <code>zz</code>) keep you oriented.</li></ul><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./10-motions.html"><strong>Chapter 10 — Motions</strong></a></p><p>We&#39;ll explore Vim&#39;s motion system—the grammar that powers every editing command.</p>`,73)])])}const m=t(s,[["render",d]]);export{u as __pageData,m as default};
